  ('aboriginal-d0d1b9a2-moex-00103', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-113-519af93a', 'sub-aboriginal-d0d1b9a2-03', NULL, 'single_choice', '配合行政院組織改造，「行政院環境保護署」於112年8月22日升格改制為「環境部」。依決算法 規定，其112年度單位決算之辦理，下列敘述何者正確？', '["編兩本，組織改造前後之決算，各由行政院環境保護署及環境部分別編造", "編兩本，組織改造前後之決算，由環境部代為分別編造", "編一本，由行政院環境保護署一併編造", "編一本，由環境部一併編造"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:04+00:00", "source_pdf_sha1": "b320891c5923", "answer_pdf_sha1": "bef9620a3afb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "506", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計法規概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
